#!/usr/bin/env python3
"""
Build comprehensive CPT, ICD-10, specialty hierarchy, and NCCI bundle databases.
Generates:
  - cpt_database.json (2000+ CPT codes)
  - icd10_database.json (500+ ICD-10 codes)
  - specialty_hierarchy.json
  - ncci_bundles.json (200+ bundle pairs)

Uses real CMS wRVU values where known; estimates marked with "estimated": true.
"""

import json
import os

OUTPUT_DIR = os.path.dirname(os.path.abspath(__file__))

###############################################################################
# HELPER
###############################################################################

def cpt(code, desc, cat, subcat, specialty, wrvu, global_period=0,
         modifiers=None, bilateral=False, addon=False, cosurgeon=False,
         assistant=False, tier=1, family="", inclusive=None, never_with=None,
         estimated=False):
    return {
        "code": str(code),
        "description": desc,
        "category": cat,
        "subcategory": subcat,
        "specialty": specialty if isinstance(specialty, list) else [specialty],
        "work_rvu": wrvu,
        "estimated": estimated,
        "global_period_days": global_period,
        "typical_modifiers": modifiers or [],
        "bilateral_eligible": bilateral,
        "addon_code": addon,
        "cosurgeon_eligible": cosurgeon,
        "assistant_allowed": assistant,
        "hierarchy_tier": tier,
        "code_family": family,
        "inclusive_of": inclusive or [],
        "never_primary_with": never_with or []
    }

###############################################################################
# E/M CODES (99201-99499)
###############################################################################

def build_em_codes():
    codes = []

    # Office/Outpatient NEW (99202-99205) - 99201 deleted 2021
    for i, (c, desc, rvu) in enumerate([
        ("99202", "Office/outpatient visit, new patient, straightforward MDM", 0.93),
        ("99203", "Office/outpatient visit, new patient, low MDM", 1.60),
        ("99204", "Office/outpatient visit, new patient, moderate MDM", 2.60),
        ("99205", "Office/outpatient visit, new patient, high MDM", 3.50),
    ]):
        codes.append(cpt(c, desc, "E/M", "Office Visit - New", "internal_medicine", rvu,
                         family="office_new"))

    # Office/Outpatient ESTABLISHED (99211-99215)
    for c, desc, rvu in [
        ("99211", "Office/outpatient visit, established, may not require physician", 0.18),
        ("99212", "Office/outpatient visit, established, straightforward MDM", 0.70),
        ("99213", "Office/outpatient visit, established, low MDM", 1.30),
        ("99214", "Office/outpatient visit, established, moderate MDM", 1.92),
        ("99215", "Office/outpatient visit, established, high MDM", 2.80),
    ]:
        codes.append(cpt(c, desc, "E/M", "Office Visit - Established", "internal_medicine", rvu,
                         family="office_est"))

    # Hospital Inpatient/Observation (99221-99223, 99231-99233, 99234-99236, 99238-99239)
    for c, desc, rvu in [
        ("99221", "Initial hospital inpatient/observation, low MDM", 2.00),
        ("99222", "Initial hospital inpatient/observation, moderate MDM", 2.61),
        ("99223", "Initial hospital inpatient/observation, high MDM", 3.86),
        ("99231", "Subsequent hospital inpatient/observation, low MDM", 0.76),
        ("99232", "Subsequent hospital inpatient/observation, moderate MDM", 1.39),
        ("99233", "Subsequent hospital inpatient/observation, high MDM", 2.00),
        ("99234", "Hospital inpatient/observation same-day admit/discharge, low MDM", 2.56),
        ("99235", "Hospital inpatient/observation same-day admit/discharge, moderate MDM", 3.40),
        ("99236", "Hospital inpatient/observation same-day admit/discharge, high MDM", 4.20),
        ("99238", "Hospital discharge day management, 30 min or less", 1.28),
        ("99239", "Hospital discharge day management, more than 30 min", 1.90),
    ]:
        codes.append(cpt(c, desc, "E/M", "Hospital Inpatient", ["internal_medicine", "general_surgery"], rvu,
                         family="hospital_ip"))

    # Consultations (99241-99245, 99251-99255)
    for c, desc, rvu in [
        ("99242", "Office consultation, straightforward MDM", 1.30),
        ("99243", "Office consultation, low MDM", 2.11),
        ("99244", "Office consultation, moderate MDM", 3.28),
        ("99245", "Office consultation, high MDM", 4.00),
        ("99251", "Inpatient consultation, straightforward MDM", 0.99),
        ("99252", "Inpatient consultation, low MDM", 1.60),
        ("99253", "Inpatient consultation, moderate MDM", 2.39),
        ("99254", "Inpatient consultation, high MDM", 3.33),
        ("99255", "Inpatient consultation, high MDM (comprehensive)", 4.55),
    ]:
        codes.append(cpt(c, desc, "E/M", "Consultation", ["internal_medicine", "general_surgery"], rvu,
                         family="consult"))

    # ED Visits (99281-99285)
    for c, desc, rvu in [
        ("99281", "Emergency department visit, self-limited problem", 0.45),
        ("99282", "Emergency department visit, low to moderate severity", 0.93),
        ("99283", "Emergency department visit, moderate severity", 1.60),
        ("99284", "Emergency department visit, high severity", 2.74),
        ("99285", "Emergency department visit, high severity with life threat", 3.95),
    ]:
        codes.append(cpt(c, desc, "E/M", "Emergency Department", "emergency_medicine", rvu,
                         family="ed_visit"))

    # Critical Care (99291-99292)
    codes.append(cpt("99291", "Critical care, first 30-74 minutes", "E/M", "Critical Care",
                      ["emergency_medicine", "trauma", "pulmonology"], 4.50, family="crit_care"))
    codes.append(cpt("99292", "Critical care, each additional 30 minutes", "E/M", "Critical Care",
                      ["emergency_medicine", "trauma", "pulmonology"], 2.25, addon=True, family="crit_care"))

    # Nursing Facility
    for c, desc, rvu in [
        ("99304", "Nursing facility initial visit, low MDM", 1.50),
        ("99305", "Nursing facility initial visit, moderate MDM", 2.10),
        ("99306", "Nursing facility initial visit, high MDM", 2.95),
        ("99307", "Nursing facility subsequent visit, straightforward", 0.56),
        ("99308", "Nursing facility subsequent visit, low MDM", 0.97),
        ("99309", "Nursing facility subsequent visit, moderate MDM", 1.37),
        ("99310", "Nursing facility subsequent visit, high MDM", 2.03),
    ]:
        codes.append(cpt(c, desc, "E/M", "Nursing Facility", "internal_medicine", rvu,
                         estimated=True, family="nursing_fac"))

    # Prolonged Services
    for c, desc, rvu in [
        ("99354", "Prolonged service, office, first hour", 2.10),
        ("99355", "Prolonged service, office, each additional 30 min", 2.10),
        ("99356", "Prolonged service, inpatient, first hour", 2.10),
        ("99357", "Prolonged service, inpatient, each additional 30 min", 2.10),
        ("99417", "Prolonged office visit, each additional 15 min (add-on)", 1.17),
    ]:
        codes.append(cpt(c, desc, "E/M", "Prolonged Services", "internal_medicine", rvu,
                         addon=(c in ["99355","99357","99417"]), estimated=True, family="prolonged"))

    # Care Management / Chronic Care
    for c, desc, rvu in [
        ("99490", "Chronic care management, 20 min/month", 0.61),
        ("99491", "Chronic care management, 30 min/month by physician", 1.36),
        ("99487", "Complex chronic care management, 60 min/month", 1.00),
        ("99489", "Complex chronic care management, each additional 30 min", 0.50),
        ("99457", "Remote physiologic monitoring treatment, first 20 min", 0.61),
        ("99458", "Remote physiologic monitoring treatment, add'l 20 min", 0.61),
        ("99453", "Remote physiologic monitoring setup", 0.00),
        ("99454", "Remote physiologic monitoring device supply", 0.00),
        ("99473", "Self-measured BP monitoring, patient education/training", 0.50),
        ("99474", "Self-measured BP monitoring, physician review", 0.50),
    ]:
        codes.append(cpt(c, desc, "E/M", "Care Management", "internal_medicine", rvu,
                         estimated=True, family="care_mgmt"))

    # Transitional Care Management
    for c, desc, rvu in [
        ("99495", "Transitional care management, moderate complexity", 2.78),
        ("99496", "Transitional care management, high complexity", 3.79),
    ]:
        codes.append(cpt(c, desc, "E/M", "Transitional Care", "internal_medicine", rvu,
                         family="tcm"))

    # Advance Care Planning
    codes.append(cpt("99497", "Advance care planning, first 30 min", "E/M", "Advance Care Planning",
                      "internal_medicine", 1.50, estimated=True, family="acp"))
    codes.append(cpt("99498", "Advance care planning, each additional 30 min", "E/M", "Advance Care Planning",
                      "internal_medicine", 1.40, addon=True, estimated=True, family="acp"))

    return codes

